@@ -0,0 +1,238 @@
+import { describe, it, expect, beforeEach } from 'vitest';
+import {
+  EmailAdapter,
+  InMemoryTransport,
+  FailingTransport,
+} from '../../src/adapters/email.adapter.js';
+import type { NotificationPayload } from '../../src/models/notification.js';
+
+function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
+  return {
+    type: 'order:confirmation',
+    recipient: 'alice@example.com',
+    subject: 'Order Confirmation: order-1',
+    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
+    channel: 'email',
+    priority: 'normal',
+    metadata: { orderId: 'order-1', notificationId: 'notif-0001' },
+    ...overrides,
+  };
+}
+
+describe('EmailAdapter', () => {
+  let transport: InMemoryTransport;
+  let adapter: EmailAdapter;
+
+  beforeEach(() => {
+    transport = new InMemoryTransport();
+    adapter = new EmailAdapter({
+      fromAddress: 'noreply@taskflow.com',
+      replyToAddress: 'support@taskflow.com',
+      transport,
+    });
+  });
+
+  it('has channel set to email', () => {
+    expect(adapter.channel).toBe('email');
+  });
+
+  describe('resolveRecipient', () => {
+    it('normalizes email to lowercase and trims whitespace', () => {
+      expect(adapter.resolveRecipient('  Alice@Example.COM  ')).toBe('alice@example.com');
+    });
+
+    it('throws on invalid email', () => {
+      expect(() => adapter.resolveRecipient('not-an-email')).toThrow('Invalid email recipient');
+    });
+
+    it('throws on empty string', () => {
+      expect(() => adapter.resolveRecipient('')).toThrow('Invalid email recipient');
+    });
+
+    it('accepts valid emails', () => {
+      expect(adapter.resolveRecipient('user@domain.co')).toBe('user@domain.co');
+      expect(adapter.resolveRecipient('a+b@c.org')).toBe('a+b@c.org');
+    });
+  });
+
+  describe('renderEmail', () => {
+    it('renders order:confirmation template with metadata', () => {
+      const payload = makePayload();
+      const email = adapter.renderEmail(payload);
+
+      expect(email.from).toBe('noreply@taskflow.com');
+      expect(email.replyTo).toBe('support@taskflow.com');
+      expect(email.to).toBe('alice@example.com');
+      expect(email.subject).toBe('Order Confirmation: order-1');
+      expect(email.html).toContain('Order Confirmed');
+      expect(email.html).toContain('order-1');
+      expect(email.text).toContain('Order Confirmed');
+      expect(email.text).toContain('Order ID: order-1');
+      expect(email.text).toContain('TaskFlow Pro');
+    });
+
+    it('renders order:status-update template', () => {
+      const payload = makePayload({
+        type: 'order:status-update',
+        subject: 'Order Update: order-1',
+        body: 'Your order status has changed from pending to confirmed.',
+        metadata: { orderId: 'order-1', newStatus: 'confirmed', notificationId: 'notif-0002' },
+      });
+      const email = adapter.renderEmail(payload);
+
+      expect(email.html).toContain('Order Status Update');
+      expect(email.html).toContain('confirmed');
+      expect(email.text).toContain('New Status: confirmed');
+    });
+
+    it('renders user:welcome template', () => {
+      const payload = makePayload({
+        type: 'user:welcome',
+        subject: 'Welcome!',
+        body: 'Welcome to the platform, Alice!',
+        metadata: { notificationId: 'notif-0003' },
+      });
+      const email = adapter.renderEmail(payload);
+
+      expect(email.html).toContain('Welcome to TaskFlow Pro!');
+      expect(email.text).toContain('Welcome to TaskFlow Pro!');
+      expect(email.text).toContain('Welcome to the platform, Alice!');
+    });
+
+    it('renders user:profile-updated template', () => {
+      const payload = makePayload({
+        type: 'user:profile-updated',
+        subject: 'Profile Updated',
+        body: 'Your profile has been updated.',
+        metadata: { notificationId: 'notif-0004' },
+      });
+      const email = adapter.renderEmail(payload);
+
+      expect(email.html).toContain('Profile Updated');
+      expect(email.text).toContain('Profile Updated');
+    });
+
+    it('escapes HTML in body to prevent XSS', () => {
+      const payload = makePayload({
+        body: '<script>alert("xss")</script>',
+      });
+      const email = adapter.renderEmail(payload);
+
+      expect(email.html).not.toContain('<script>');
+      expect(email.html).toContain('&lt;script&gt;');
+    });
+
+    it('omits replyTo when not configured', () => {
+      const noReplyAdapter = new EmailAdapter({
+        fromAddress: 'noreply@taskflow.com',
+        transport,
+      });
+      const email = noReplyAdapter.renderEmail(makePayload());
+      expect(email.replyTo).toBeUndefined();
+    });
+  });
+
+  describe('send', () => {
+    it('sends email and returns success', async () => {
+      const payload = makePayload();
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(true);
+      expect(result.notificationId).toBe('notif-0001');
+      expect(result.channel).toBe('email');
+      expect(result.error).toBeUndefined();
+
+      expect(transport.sent).toHaveLength(1);
+      expect(transport.sent[0]?.to).toBe('alice@example.com');
+      expect(transport.sent[0]?.from).toBe('noreply@taskflow.com');
+    });
+
+    it('returns failure when transport throws', async () => {
+      const failAdapter = new EmailAdapter({
+        fromAddress: 'noreply@taskflow.com',
+        transport: new FailingTransport('Connection refused'),
+      });
+
+      const result = await failAdapter.send(makePayload());
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('Connection refused');
+      expect(result.channel).toBe('email');
+    });
+
+    it('returns failure for invalid recipient', async () => {
+      const payload = makePayload({ recipient: 'bad-email' });
+      const result = await adapter.send(payload);
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid email recipient');
+    });
+
+    it('uses notificationId from metadata', async () => {
+      const payload = makePayload({
+        metadata: { notificationId: 'custom-id' },
+      });
+      const result = await adapter.send(payload);
+      expect(result.notificationId).toBe('custom-id');
+    });
+
+    it('falls back to unknown when no notificationId in metadata', async () => {
+      const payload = makePayload({ metadata: undefined });
+      const result = await adapter.send(payload);
+      expect(result.notificationId).toBe('unknown');
+    });
+
+    it('sends multiple emails independently', async () => {
+      await adapter.send(makePayload({ recipient: 'a@example.com' }));
+      await adapter.send(makePayload({ recipient: 'b@example.com' }));
+
+      expect(transport.sent).toHaveLength(2);
+      expect(transport.sent[0]?.to).toBe('a@example.com');
+      expect(transport.sent[1]?.to).toBe('b@example.com');
+    });
+  });
+
+  describe('InMemoryTransport', () => {
+    it('records sent emails and increments messageId', async () => {
+      const t = new InMemoryTransport();
+      const email = adapter.renderEmail(makePayload());
+
+      const r1 = await t.sendMail(email);
+      const r2 = await t.sendMail(email);
+
+      expect(r1.messageId).toBe('msg-1');
+      expect(r2.messageId).toBe('msg-2');
+      expect(r1.accepted).toBe(true);
+      expect(t.sent).toHaveLength(2);
+    });
+
+    it('clears sent emails', async () => {
+      const t = new InMemoryTransport();
+      await t.sendMail(adapter.renderEmail(makePayload()));
+      t.clear();
+      expect(t.sent).toHaveLength(0);
+    });
+  });
+
+  describe('FailingTransport', () => {
+    it('throws with configured error message', async () => {
+      const t = new FailingTransport('Custom error');
+      const email = adapter.renderEmail(makePayload());
+      await expect(t.sendMail(email)).rejects.toThrow('Custom error');
+    });
+
+    it('uses default error message when none provided', async () => {
+      const t = new FailingTransport();
+      const email = adapter.renderEmail(makePayload());
+      await expect(t.sendMail(email)).rejects.toThrow('SMTP connection failed');
+    });
+  });
+
+  describe('integration with NotificationService pattern', () => {
+    it('conforms to NotificationAdapter interface', () => {
+      // Verify the adapter satisfies the interface contract
+      expect(typeof adapter.channel).toBe('string');
+      expect(typeof adapter.send).toBe('function');
+    });
+  });
+});
